export function listExpandedProgramFeatures() {
  return PROGRAM_MODULE_BLUEPRINTS.flatMap((module) => module.featureContracts.map((feature) => ({ ...feature })));
}

export function listExpandedProgramModules() {
  return PROGRAM_MODULE_BLUEPRINTS.map((module) => ({
    id: module.id,
    name: module.name,
    apiPrefix: module.apiPrefix,
    uiPages: [...module.uiPages],
    dataEntities: [...module.entities],
    featureCount: module.featureContracts.length
  }));
}

export function listExpandedProgramRunbooks() {
  return PROGRAM_RUNBOOKS.map((item) => ({ ...item, steps: [...item.steps] }));
}

export function listExpandedProgramCheckpoints() {
  return PROGRAM_RELEASE_CHECKPOINTS.map((item) => ({ ...item, requirements: [...item.requirements] }));
}
